import format from "date-fns/format";
import React, { useEffect, useState } from "react";
import { Link, useLocation } from "react-router-dom";
import AppointmentService from "../../../services/appointment.services";
import DoctorService from "../../../../admin/services/doctors.service";
import AttachmentService from "../../../services/attachment.service";
import CircularProgress from "@mui/material/CircularProgress";
import { questions, labels } from "../../../../common/questions";
import { useTranslation } from "react-i18next";
function AppointmentDetails() {
  const [t, i18next] = useTranslation();
  let location = useLocation();
  const [state, setState] = useState({
    ...location?.state,
  });
  const [doctorInfo, setDoctorInfo] = useState();
  const [appointment, setAppointment] = useState();
  const [attachments, setAttachments] = useState([]);
  const [message, setMessage] = useState();

  const [travelPreferences, setTravelPreferences] = useState(
    JSON.parse(state?.travelPreferences)
  );
  const [loading, setLoading] = useState(false);
  useEffect(async () => {
    const responseAppointment = await AppointmentService.getAppointmentById(
      state?.id
    );
    setAppointment(responseAppointment?.body);
    // const response = await DoctorService.getDoctorByID(state?.doctorId);
    // setDoctorInfo(response?.body);

    if (responseAppointment?.body?.attachments?.length > 0) {
      setLoading(true);
      let responseAttachment;
      responseAppointment?.body?.attachments.map(async (att, index) => {
        responseAttachment = await AttachmentService.getAttachmentById(att.id);
        setAttachments((prev) => [...prev, responseAttachment?.body]);
        if (index === responseAppointment?.body?.attachments?.length - 1)
          setLoading(false);
      });
    }
  }, []);

  function download(file) {
    var element = document.createElement("a");
    element.setAttribute("href", file.fileUrl);
    element.setAttribute("download", file.fileName);
    element.style.display = "none";
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  }
  async function ExportMedicalDetails(s) {
    setMessage();
    console.log(`AppointmentDetails :: ExportMedicalDetails: ${JSON.stringify(s)}`)
    const responseAppointmentDetails =
      await AppointmentService.exportAppointmentDetails(s?.id);
    if (
      !!!responseAppointmentDetails.success &&
      !responseAppointmentDetails.success
    ) {
      setMessage(
        !!responseAppointmentDetails.message &&
          responseAppointmentDetails.message
      );
      return;
    }
    download(responseAppointmentDetails?.body);
  }
  async function ExportTravelPreferences(appointmentId) {
    setMessage();
    const responseTravelPreferences =
      await AppointmentService.exportTravelPreferences(appointmentId);
    if (
      !!!responseTravelPreferences.success &&
      !responseTravelPreferences.success
    ) {
      setMessage(
        !!responseTravelPreferences.message && responseTravelPreferences.message
      );
      return;
    }
    download(responseTravelPreferences?.body);
  }
  return (
    <div className="content">
      <div className="container">
        <Link
          to="/account-appointments"
          className="btn btn-primary bd-highlight"
        >
          <i className="fas  fa-arrow-left"></i>{" "}
          {t("AppointmentsComponent.BackToAppointments")}
        </Link>
        <div className="row patient-details-flex">
          {message?.map((m, i) => (
            <div
              key={i}
              className="invalid-feedback d-block mb-2"
              style={{
                margin:
                  i18next.language === "en" ? "10px 0 0 15px" : "10px 15px 0 0",
              }}
            >
              {m}
            </div>
          ))}
          <div className="col-md-6">
            <div className="card booking-card">
              <h3 className="p-2 bd-highlight text-center">
                {t("AppointmentsComponent.MedicalServiceDetails")}
                <a
                  title={t("Export")}
                  style={{
                    color: "darkblue",
                    padding:
                      i18next.language === "en" ? "0 0 0 5px" : "0 5px 0 0",
                    cursor: "pointer",
                  }}
                  onClick={() => {
                    ExportMedicalDetails(state);
                  }}
                >
                  <i className="fa fa-file-word"></i>
                </a>
              </h3>

              <div className="card-body d-flex justify-content-center">
                <ul className="list-group" style={{ width: "40rem" }}>
                  <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                    <div className="col-7">
                      {t("AppointmentsComponent.BookingNumber")}:
                    </div>
                    <div className="col-7">{state?.id}</div>
                  </li>
                  <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                    <div className="col-7">
                      {t("AppointmentsComponent.AppointmentDate")}:
                    </div>
                    <div className="col-7">
                      {state?.appointmentDate &&
                        format(new Date(state?.appointmentDate), "dd/MM/yyyy")}
                    </div>
                  </li>
                  <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                    <div className="col-7">
                      {t("AppointmentsComponent.AppointmentBookedWith")}:
                    </div>
                    <div className="col-7">{`Dr. ${state?.doctorFirstName} ${
                      state?.doctorLastName !== null
                        ? state?.doctorLastName
                        : ""
                    }`}</div>
                  </li>
                  <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                    <div className="col-7">
                      {t("AppointmentsComponent.Symptoms")}:
                    </div>
                    <div className="col-7">{state?.symptoms}</div>
                  </li>
                  <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                    <div className="col-7">
                      {t("AppointmentsComponent.Attachments")}:
                    </div>
                    <div className="col-6">
                      {loading ? (
                        <CircularProgress />
                      ) : (
                        attachments?.map((attachment, i) => {
                          return (
                            <div key={i}>
                              <span> {attachment?.fileName}</span>
                              <a
                                key={i}
                                href={attachment?.fileUrl}
                                download={attachment?.fileName}
                              >
                                <i
                                  className="fa fa-download"
                                  style={{
                                    color: "#17a2b8",
                                    padding:
                                      i18next.language === "en"
                                        ? "0 0 0 5px"
                                        : "0 5px 0 0",
                                  }}
                                ></i>
                              </a>
                            </div>
                          );
                        })
                      )}
                    </div>
                  </li>
                </ul>
              </div>
            </div>
          </div>
          {state?.travelPreferences && (
            <div className="col-md-6">
              <div className="card booking-card">
                <h3 className="p-2 bd-highlight text-center">
                  {t("AppointmentsComponent.TravelPreferences")}
                  <a
                    title={t("Export")}
                    style={{
                      color: "darkblue",
                      padding:
                        i18next.language === "en" ? "0 0 0 5px" : "0 5px 0 0",
                      cursor: "pointer",
                    }}
                    onClick={() => {
                      ExportTravelPreferences(state?.id);
                    }}
                  >
                    <i className="fa fa-file-word"></i>
                  </a>
                </h3>
                {questions?.map((q) =>
                  travelPreferences[q?.selectionCondition] === "Yes" ? (
                    <div className="card-body d-flex justify-content-center">
                      <ul className="list-group" style={{ width: "40rem" }}>
                        {" "}
                        <h4 className="mt-n4" style={{ textAlign: "start" }}>
                          {q?.title} {!!q?.fields}
                        </h4>
                        {q?.fields?.map((f) => (
                          <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                            <div className="col-6">{labels[f.name]}</div>
                            <div className="col-6">
                              {travelPreferences[f.name]}
                            </div>
                          </li>
                        ))}
                      </ul>
                    </div>
                  ) : (
                    <div className="card-body d-flex justify-content-center">
                      <ul className="list-group" style={{ width: "40rem" }}>
                        {" "}
                        <h4 className="mt-n4" style={{ textAlign: "start" }}>
                          {q.title}
                        </h4>
                        <li className="list-group-item d-flex justify-content-between align-items-center py-1">
                          <div className="col-12">
                            {" "}
                            {"Not interested, maybe later"}
                          </div>
                        </li>
                      </ul>
                    </div>
                  )
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default AppointmentDetails;
